// ==================== 精确60甲子纳音 ====================
const NAYIN_60=[
'海中金','炉中火','大林木','路旁土','剑锋金','山头火','涧下水','城头土','白蜡金','杨柳木','井泉水','屋上土','霹雳火','松柏木','长流水','砂中金','山下火','平地木','壁上土','金箔金','覆灯火','天河水','大驿土','钗钏金','桑柘木','石榴木','大海水','石榴木','大海水','海中金','炉中火','大林木','路旁土','剑锋金','山头火','涧下水','城头土','白蜡金','杨柳木','井泉水','屋上土','霹雳火','松柏木','长流水','砂中金','山下火','平地木','壁上土','金箔金','覆灯火','天河水','大驿土','钗钏金','桑柘木','石榴木','大海水','石榴木','大海水','海中金'
];
function getNayin(stemIdx,branchIdx){
    // 精确60甲子纳音：按 stem*6+branch*5 计算
    let idx=Math.floor(((stemIdx%10)*6 + (branchIdx%12)*5)%60/2)%30;
    return NAYIN_60[idx];
}

