// ==================== 六亲与子女 ====================
function analyzeLiuQin(dGZ,ps,gender){
    let t='',de=SE[dGZ.s],ds=dGZ.s;
    let nGZ=ps[0],mGZ=ps[1],rGZ=ps[2],sGZ=ps[3];
    // 年柱父母
    let nShi=getShiShen(ds,nGZ.s);
    let mShi=getShiShen(ds,mGZ.s);
    t+='<p style="color:var(--accent);text-indent:0;">👨‍👩‍👧 日主'+S[ds]+de+'，你的六亲画像——</p>';
    
    t+='<p><strong>【父母缘】</strong>年柱为<strong>'+S[nGZ.s]+B[nGZ.b]+'</strong>（'+nShi+'），代表祖辈与父母根基。';
    let nShiText='';let nYGZ=S[nGZ.s]+B[nGZ.b];
    if(nShi==='正印'||nShi==='偏印')nShiText='印星在年——你从小得长辈呵护，家庭如坚实后盾。母亲（或母系长辈）对你的性格塑造影响最深。年柱'+nYGZ+'的纳音为'+getNayin(nGZ.s,nGZ.b)+'，祖上或有一技之长传承。';
    else if(nShi==='正财'||nShi==='偏财')nShiText='财星在年——父亲（或父系长辈）对你的价值观影响深远。你可能从小就比较务实，对金钱和资源有早熟的认知。年柱'+nYGZ+'的配置说明家庭物质基础不差，但真正的积累靠你自己。';
    else if(nShi==='正官'||nShi==='七杀')nShiText='官杀在年——家教较严，从小被要求守规矩、懂分寸。这让你长大后自律性强、做事靠谱，但童年可能少了一些无忧无虑的自由。年柱'+nYGZ+'自带威严，祖辈中或有从政从军之人。';
    else if(nShi==='食神'||nShi==='伤官')nShiText='食伤在年——你的家庭氛围比较宽松自由，长辈给了你足够的发展空间。你可能从小就表现出某方面的天赋（文艺、口才、创意），这与家庭环境的鼓励分不开。';
    else nShiText='年柱'+nYGZ+'配置独特——家庭背景和成长经历塑造了你不同于同龄人的视角和韧性。';
    t+=nShiText+'</p>';

    let biJieCount=(ps.filter(p=>{let s=getShiShen(ds,p.s);return s==='比肩'||s==='劫财';}).length);
    t+='<p><strong>【兄弟姐妹】</strong>月柱<strong>'+S[mGZ.s]+B[mGZ.b]+'</strong>（'+mShi+'）——';
    if(biJieCount>=3)t+='你命中比劫极旺——兄弟姐妹多或朋友多如手足。他们是你生命中不可或缺的一部分，既是你最坚实的后盾、也可能是你最大的竞争来源。学会在合作与独立之间找到平衡，是你一生的课题。';
    else if(biJieCount>=2)t+='你命中带比劫——有兄弟姐妹缘分，或朋友在你生命中扮演了家人的角色。你们彼此成就也彼此较量，这种关系让你更早学会了与人相处的能力。';
    else if(biJieCount===1)t+='命中有一颗比劫——你可能是独生子女，或与手足年龄差距较大。这让你更早学会了独立思考和独处的能力。你的朋友不多但精，一旦认定的人就会很长久。';
    else t+='比劫不显——独生子女概率大，或与手足缘分较浅。但你因此更早学会了依靠自己。独立不是孤独，是你最强的底色。';
    t+='</p>';

    let sShi=getShiShen(ds,sGZ.s);
    let shiShangCount=(ps.filter(p=>{let s=getShiShen(ds,p.s);return s==='食神'||s==='伤官';}).length);
    t+='<p><strong>【子女运】</strong>时柱<strong>'+S[sGZ.s]+B[sGZ.b]+'</strong>（'+sShi+'）——';
    if(shiShangCount>=3)t+='食伤极旺——子女缘分非常深厚，可能不止一个孩子。TA们聪明有主见，小时候需要你多花心思引导而非命令。长大后TA们会成为你的骄傲——有才、独立、有自己的世界。';
    else if(shiShangCount>=2)t+='食伤较旺——子女缘分好。TA们天生有自己的想法和节奏，教育方式宜引导而非强制。晚年你会在TA们身上看到自己年轻时的影子。';
    else if(sShi==='食神')t+='时柱带食神——子女是你晚年的福星和开心果。与TA们相处轻松愉快，你对TA的要求不高但TA往往给你惊喜。';
    else if(sShi==='伤官')t+='时柱带伤官——子女聪明有才但叛逆期可能较长。需要你比别的父母多一份耐心和智慧。但熬过青春期，TA们的才华会让你觉得一切都值。';
    else if(sShi==='正印'||sShi==='偏印')t+='时柱带印星——与子女的关系偏向传统的"慈母孝子"型。TA们尊重你、愿意听你的建议，晚年有依靠。';
    else t+='子女星不显——缘分不在多而在精。可能是独生子女，或与子女的相处模式比较特别（如聚少离多但感情深厚）。大运逢之则子女缘自来。';
    t+='</p>';

    return t;
}

// ==================== 贵人运与社交 ====================
function analyzeGuiren(dGZ,ps,ssha,gys){
    let t='',de=SE[dGZ.s],ds=dGZ.s;
    t+='<p style="color:var(--accent);text-indent:0;">🌟 日主'+S[ds]+de+'，谁是你的贵人——</p>';

    let hasTY=ssha.some(s=>s.includes('天乙'));
    let hasTJ=ssha.some(s=>s.includes('太极'));
    let hasTD=ssha.some(s=>s.includes('天德'));
    let hasYD=ssha.some(s=>s.includes('月德'));
    let hasFX=ssha.some(s=>s.includes('福星'));
    let hasWen=ssha.some(s=>s.includes('文昌'));

    if(hasTY||hasTJ||hasTD||hasYD||hasFX){
        t+='<p><strong>【命中贵人】</strong>你命中带有：';
        let gList=[];
        if(hasTY)gList.push('天乙贵人（最大的吉星，逢凶化吉）');
        if(hasTJ)gList.push('太极贵人（智慧型贵人，导师类人物）');
        if(hasTD)gList.push('天德贵人（上天庇佑，阴德护身）');
        if(hasYD)gList.push('月德贵人（女性贵人、长辈助力）');
        if(hasFX)gList.push('福星贵人（自带福气，遇难呈祥）');
        t+=gList.join('、')+'。</p>';
        t+='<p>这些贵人会在你人生关键节点出现——可能是一个提携你的上司、一个点醒你的朋友、或一个素不相识却帮了你一把的陌生人。你要做的是保持开放的心态，别拒绝社交。</p>';
    }else{
        t+='<p><strong>【命中贵人】</strong>你的贵人星不太显，但这不是说你没有贵人。你的贵人藏在日常里——那些默默陪你、支持你的人。他们不张扬，但一直都在。</p>';
    }

    let yongWx=gys.xs[0];
    let guiTips={木:'五行属木的人（正直温和型）是你的天然贵人。多接触从事教育、文化、医疗行业的人。',火:'五行属火的人（热情开朗型）是你的天然贵人。多接触从事传媒、餐饮、互联网行业的人。',土:'五行属土的人（踏实稳重型）是你的天然贵人。多接触从事地产、金融、建筑行业的人。',金:'五行属金的人（果断坚毅型）是你的天然贵人。多接触从事法律、金融、管理行业的人。',水:'五行属水的人（聪明灵活型）是你的天然贵人。多接触从事贸易、物流、IT行业的人。'};
    t+='<p><strong>【社交磁场】</strong>'+guiTips[yongWx]+'</p>';

    // 小人与防范
    let jiWx=gys.js[gys.js.length-1]||'';
    if(jiWx){
        t+='<p><strong>【留心之人】</strong>五行属<strong>'+jiWx+'</strong>的人，可能和你气场不太合。这不是说他们不好，而是你们的能量天然相克——合作时容易摩擦、沟通成本高。知道就好，不必刻意避开，但重要合作时多留一个心眼。</p>';
    }

    return t;
}

// ==================== 学业与考运 ====================
function analyzeXueye(dGZ,ps,ssha){
    let t='',de=SE[dGZ.s],ds=dGZ.s;
    let yinCount=(ps.filter(p=>{let s=getShiShen(ds,p.s);return s==='正印'||s==='偏印';}).length);
    let hasWen=ssha.some(s=>s.includes('文昌'));
    let hasXue=ssha.some(s=>s.includes('学堂'));
    let hasTJ=ssha.some(s=>s.includes('太极'));

    t+='<p style="color:var(--accent);text-indent:0;">📚 日主'+S[ds]+de+'，你的学业密码——</p>';

    t+='<p><strong>【学习天赋】</strong>';
    if(yinCount>=2)t+='命中印星较旺——你天生有学习的慧根。别人啃不动的书你能啃下来，考试运也优于常人。适合走学术路线或需要持续学习的职业（律师、医生、教授）。';
    else if(yinCount===1)t+='命中有一颗印星——你有基本的学习能力，但需要找到自己真正感兴趣的方向才能激发潜力。强迫式学习对你效果不好。';
    else t+='印星不显——你不一定是"书本型"的人，但有很强的实践学习能力。做中学、用中学才是你的最佳路径。职业技能培训比传统学位更适合你。';
    t+='</p>';

    if(hasWen||hasXue||hasTJ){
        t+='<p><strong>【考运加成】</strong>你命中带有：';
        let kList=[];
        if(hasWen)kList.push('文昌星（考试运佳，关键时刻发挥超常）');
        if(hasXue)kList.push('学堂（对新知识吸收快，适合持续进修）');
        if(hasTJ)kList.push('太极贵人（在深度思考和研究上有天赋）');
        t+=kList.join('、')+'。</p>';
    }

    let cs=getChangSheng12(ds,dGZ.b);
    t+='<p><strong>【最佳学习方式】</strong>日柱<strong>'+cs.n+'</strong>状态——';
    if(de==='木')t+='适合小组讨论、互动式学习。坐不住的你，边做边学效率最高。';
    else if(de==='火')t+='适合快节奏、有挑战的学习。枯燥的重复会让你失去兴趣，找有竞争感的模式。';
    else if(de==='土')t+='适合按部就班、体系化的学习。你需要完整的框架，循序渐进最适合你。';
    else if(de==='金')t+='适合逻辑清晰、有规则的学习。你喜欢搞清楚"为什么"，理解原理比死记硬背重要。';
    else t+='适合灵活多变、自由探索的学习。你不喜欢被框住，按照自己的节奏走最有效。';
    t+='</p>';

    return t;
}

