function analyzeBirthGeo(y,m,d,h,ps,dGZ){
    let t='',de=SE[dGZ.s],ds=dGZ.s;
    let lon=parseFloat(document.getElementById('lonVal').value)||116.4;
    let btnTxt=document.getElementById('birthBtn').textContent;
    let locName=btnTxt.includes('请选择')?'未指定出生地':btnTxt;
    let origH=parseInt(document.getElementById('bhour').value)||h;
    t+='<p style="color:var(--accent);text-indent:0;">📍 出生时空——'+locName+'，'+y+'年'+m+'月'+d+'日'+origH+'时</p>';
    // 节气
    let jieqi=[{n:'立春',m:2,d:4,dsc:'万物复苏，阳气初升。带着破旧立新的冲劲——像初春第一株嫩芽，生命力顽强。'},
        {n:'雨水',m:2,d:19,dsc:'春雨润物，水汽充沛。心思细腻，善解人意，如春雨般潜移默化影响他人。'},
        {n:'惊蛰',m:3,d:6,dsc:'春雷乍响。骨子里有股爆发力——平时不显，关键时刻一鸣惊人。'},
        {n:'春分',m:3,d:21,dsc:'昼夜平分，阴阳调和。性格平衡感强，是天生的调停者。'},
        {n:'清明',m:4,d:5,dsc:'天清地明。内心澄澈有灵气，对美好事物有天然感知力。'},
        {n:'谷雨',m:4,d:20,dsc:'雨生百谷。稳重有耐心，不急不躁，等待收获。'},
        {n:'立夏',m:5,d:6,dsc:'夏日初立，火气始升。热情开始被点燃，行动力强。'},
        {n:'小满',m:5,d:21,dsc:'万物小满。知足常乐，懂得"够好就行"的智慧。'},
        {n:'芒种',m:6,d:6,dsc:'忙于播种。勤劳是你的底色，相信付出终有回报。'},
        {n:'夏至',m:6,d:21,dsc:'阳气最盛。你天生带光，走到哪里都是焦点。'},
        {n:'小暑',m:7,d:7,dsc:'暑气渐起。内心有热情，但需防"过热"伤身。'},
        {n:'大暑',m:7,d:23,dsc:'最热时节。你的能量峰值高，但需学会"节能"。'},
        {n:'立秋',m:8,d:8,dsc:'秋意初来。理性开始觉醒，做事越来越有条理。'},
        {n:'处暑',m:8,d:23,dsc:'暑气消退。冷静是你的超能力，不随波逐流。'},
        {n:'白露',m:9,d:8,dsc:'露水渐白。内心细腻，追求品质和精致。'},
        {n:'秋分',m:9,d:23,dsc:'昼夜均分。公正公平是你的信条，不偏不倚。'},
        {n:'寒露',m:10,d:8,dsc:'露水将寒。外表冷静内心温暖，是反差型人格。'},
        {n:'霜降',m:10,d:23,dsc:'霜降大地。坚韧是你的底色，越冷越清醒。'},
        {n:'立冬',m:11,d:7,dsc:'冬日开始。内敛深沉，擅长把能量储存起来。'},
        {n:'小雪',m:11,d:22,dsc:'雪意初现。安静而有力量，沉默时在积蓄。'},
        {n:'大雪',m:12,d:7,dsc:'大雪纷飞。内心世界丰富，有诗人气质。'},
        {n:'冬至',m:12,d:22,dsc:'一阳初生。在最暗时看到了光——韧性惊人，绝地反击型。'},
        {n:'小寒',m:1,d:6,dsc:'寒意渐深。冷静自持，不容易被情绪左右。'},
        {n:'大寒',m:1,d:20,dsc:'最寒时节。耐力超群，熬过冬天就是春天。'}];
    let foundJq=jieqi[0],minDiff=365;
    jieqi.forEach(jq=>{let diff=Math.abs((m*31+d)-(jq.m*31+jq.d));if(diff<minDiff){minDiff=diff;foundJq=jq;}});
    t+='<p><strong>【节气能量】</strong>出生临近<strong>'+foundJq.n+'</strong>——'+foundJq.dsc+'</p>';

    // 真太阳时（h 已经是 render 中校正过的，这里只计算差值用于展示）
    let diffMin=Math.round((h*60)-(origH*60));
    t+='<p><strong>【真太阳时】</strong>经度<strong>'+lon.toFixed(2)+'°E</strong>，校正后时柱为<strong>'+h+'时</strong>（与北京时差'+diffMin+'分钟）。排盘时柱以此为准。</p>';

    // 方位 (东=木 西=金 南=火 北=水 中=土)
    let dirWx=lon<105?'金（西部·日落之地）——金气加持，性格果断有原则，做事有始有终。':lon<112?'土（中原·华夏腹地）——土气最旺，为人厚道做事有根基，中正平和。':lon<120?'木（东部·日出之地）——木气生发，充满朝气和创造力，接受新事物快。':'水木（东北/沿海）——水木丰沛，灵动聪慧，思维活跃。';
    t+='<p><strong>【方位五行】</strong>'+dirWx+'。</p>';

    // 季节
    let seasonDesc='';
    if(m>=3&&m<=5){seasonDesc='春季·木气当令——充满朝气和创造力。像春天的种子，天生知道方向。'+(de==='木'?'日主同木双倍加持，创意爆棚但需防理想主义。':de==='火'?'木生火得天时，学习成长加速。':de==='土'?'木克土是磨砺，风雨后更稳。':de==='金'?'木被金克的张力让你更清醒。':'水生木，滋养型人格。');}
    else if(m>=6&&m<=8){seasonDesc='夏季·火气当令——热情主动有感染力。自带阳光属性。'+(de==='火'?'日主同火能量爆棚，冲动时先数三秒。':de==='木'?'火生你得天时，成长速度领先。':de==='土'?'火泄你易耗竭，注意劳逸结合。':de==='金'?'火克你是考验，淬炼后更锋利。':'火被你克得吃力，夏天多补水多休息。');}
    else if(m>=9&&m<=11){seasonDesc='秋季·金气当令——理性果断追求完美。像秋风一样爽利。'+(de==='金'?'日主同金双金刚硬，偶尔柔一点给身边人空间。':de==='水'?'金生你——秋天运气最好做什么都顺。':de==='木'?'金克你需多些韧性，挑战即机遇。':de==='火'?'金被火克，逆风中飞翔更珍贵。':'生金泄你，秋天需补足能量。');}
    else{seasonDesc='冬季·水气当令——深沉内敛智慧。像冬天的湖水，表面平静内心丰富，大器晚成。'+(de==='水'?'日主同水极其聪明，多接触热情温暖的人事物。':de==='木'?'水生木根深后劲足，成长持续。':de==='火'?'水克火低能量季，注意保暖情绪。':de==='土'?'水被土克，需更多温暖和鼓励。':'生水泄你，少想多做出成果。');}
    t+='<p><strong>【出生季节】</strong>'+seasonDesc+'</p>';

    return t;
}

