function analyzeWuxingDetail(wc,ys){
    let t='';let total=Object.values(wc).reduce((a,b)=>a+b,0);
    let wx=['木','火','土','金','水'];
    let strongest='',weakest='';let maxC=0,minC=99;
    wx.forEach(w=>{if(wc[w]>maxC){maxC=wc[w];strongest=w;}if(wc[w]<minC){minC=wc[w];weakest=w;}});
    t+='<p>全局五行以<strong>'+strongest+'</strong>最为旺盛（'+maxC+'），以<strong>'+weakest+'</strong>最为薄弱（'+minC+'）。</p>';
    // 用神是否得力
    let ysSet=new Set(ys.ys);
    if(ysSet.has(strongest))t+='<p>最旺的五行恰好是用神，说明命局先天条件不错，能够发挥自身优势。</p>';
    let jsSet=new Set(ys.js);
    if(jsSet.has(strongest))t+='<p><em>最强的五行恰好为忌神</em>，需要特别注意调和，可通过风水、穿着颜色、职业选择等方式来平衡。</p>';
    let xsSet=new Set(ys.xs);
    if(xsSet.has(weakest))t+='<p>最弱的五行正是最需要的用神，建议通过后天补益来加强（如佩戴对应五行饰品、选择对应方位发展等）。</p>';
    return t;
}

function dayunDetailText(ddy,dGZ,st,ys){
    let dse=SE[ddy.si],dbe=BE[ddy.bi];
    let ySet=new Set(ys.ys),jSet=new Set(ys.js);
    let dyStem=S[ddy.si],dyBranch=B[ddy.bi];
    let t='';
    
    // 基础判断
    t+='<p><strong>大运干支：'+dyStem+dyBranch+'（'+dse+'+'+dbe+'）——'+ddy.nayin+'运</strong></p>';
    
    // 天干分析
    let stemIsYong=ySet.has(dse),stemIsJi=jSet.has(dse);
    let stemShiShen=getShiShen(dGZ.s,ddy.si);
    
    if(stemIsYong){
        t+='<p><strong>天干分析：</strong>天干<strong style="color:#8bc34a;">'+dyStem+dse+'为用神</strong>，'+stemShiShen+'星当令。';
        if(stemShiShen==='正财')t+='正财主稳定财运——这十年间正职收入稳步增长，适合长期投资和储蓄。偏财方面不宜冒进。';
        else if(stemShiShen==='偏财')t+='偏财主意外之财——这十年适合投资理财，但偏财来得快去得也快，需守好财根。';
        else if(stemShiShen==='正官')t+='正官主事业——这十年事业上有提升空间，适合考取证书、争取晋升，贵人多在上级。';
        else if(stemShiShen==='七杀')t+='七杀主挑战——用神七杀意味着压力能转化为动力，攻克难关后必有晋升之机。';
        else if(stemShiShen==='正印')t+='正印主贵人——这十年学习运强，长辈贵人多助，适合进修深造和考学。';
        else if(stemShiShen==='偏印')t+='偏印主智慧——这十年适合研究型工作，独立思考出成果，但人际方面宜主动些。';
        else if(stemShiShen==='食神')t+='食神主才华——这十年创意灵感充沛，适合创作和表达，生活品质上升。';
        else if(stemShiShen==='伤官')t+='伤官主表现——用神伤官才华尽显，但言辞需收敛以避小人。';
        t+='</p>';
    }else if(stemIsJi){
        t+='<p><strong>天干分析：</strong>天干<em>'+dyStem+dse+'为忌神</em>，'+stemShiShen+'星不利。';
        if(stemShiShen==='正财')t+='正财为忌——收入虽稳但开销更大，这十年存钱不易，理财需保守。';
        else if(stemShiShen==='偏财')t+='偏财为忌——投资风险极高，切忌投机，正职收入才是根基。';
        else if(stemShiShen==='正官')t+='正官为忌——事业压力大，上级苛刻，需调整心态避免硬扛。';
        else if(stemShiShen==='七杀')t+='七杀为忌——压力如山，健康和工作都面临考验，以退为进。';
        t+='</p>';
    }else{
        t+='<p><strong>天干分析：</strong>天干'+dyStem+dse+'平运，'+stemShiShen+'星中性不旺不衰。</p>';
    }
    
    // 地支分析
    let branchIsYong=ySet.has(dbe),branchIsJi=jSet.has(dbe);
    let branchCs=getChangSheng12(dGZ.s,ddy.bi);
    
    if(branchIsYong){
        t+='<p><strong>地支分析：</strong>地支<strong style="color:#8bc34a;">'+dyBranch+dbe+'为用神</strong>，根基稳固。日主于此运中十二长生为<strong>'+branchCs.n+'</strong>状态，'+(branchCs.i<=5?'能量充沛利于进取':(branchCs.i<=8?'需保养精力避免透支':'守成待机为宜'))+'。</p>';
    }else if(branchIsJi){
        t+='<p><strong>地支分析：</strong>地支<em>'+dyBranch+dbe+'为忌神</em>，根基动摇。日主于此运中十二长生为<strong>'+branchCs.n+'</strong>状态，'+(branchCs.i<=5?'虽有力气但方向不对':'身体精力需格外注意')+'。</p>';
    }

    // 总结
    if(ySet.has(dse)||ySet.has(dbe)){
        t+='<p><strong style="color:#8bc34a;">✅ 总体判断：用神运——</strong>此十年天时地利人和叠加。事业贵人多助，财运顺畅决策成功率高。<strong>积极进取大胆作为</strong>为后续打基础。人际和谐宜拓展人脉。</p>';
    }else if(jSet.has(dse)||jSet.has(dbe)){
        t+='<p><strong style="color:#ef5350;">⚠ 总体判断：忌神运——</strong>此十年考验较多。易遇阻力挫折事不顺人际矛盾增多。<strong>保守行事稳扎稳打</strong>是最佳策略。以积累实力为主多读书养精蓄锐。财务保守不借贷不投资。</p>';
    }else{
        t+='<p><strong>总体判断：平运——</strong>无大起伏。脚踏实地做好本职逐步积累。不求暴富但求稳定发展。</p>';
    }
    return t;
}

